# 导入函数库
from jqdata import *

# 初始化函数，设定基准等等
def initialize(context):
    # 设定沪深300作为基准
    set_benchmark('000905.XSHG')
    # 开启动态复权模式(真实价格)
    set_option('use_real_price', True)
    # 输出内容到日志 log.info()
    log.info('初始函数开始运行且全局只运行一次')
    # 过滤掉order系列API产生的比error级别低的log
    # log.set_level('order', 'error')

    ### 股票相关设定 ###
    # 股票类每笔交易时的手续费是：买入时佣金万分之三，卖出时佣金万分之三加千分之一印花税, 每笔交易佣金最低扣5块钱
    set_order_cost(OrderCost(close_tax=0.000, open_commission=0.00005, close_commission=0.00005, min_commission=0), type='stock')

    set_slippage(FixedSlippage(0.2))
    
    run_daily(before_market_open, time='before_open', reference_security='000905.XSHG')
      # 开盘时运行
    run_daily(market_open, time='open', reference_security='000905.XSHG')
      # 收盘后运行
    run_daily(after_market_close, time='after_close', reference_security='000905.XSHG')

## 开盘前运行函数
def before_market_open(context):
    # 输出运行时间
    log.info('函数运行时间(before_market_open)：'+str(context.current_dt.time()))

    g.security = '000905.XSHG'

